import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { CentsPipe } from '../../shared/cents.pipe';
import { Lease, LedgerEntry, Unit, User } from '../../core/models';

const U1: Unit = { id: 'u1', number: '101', bedrooms: 1, rentCents: 120000 };
const U2: Unit = { id: 'u2', number: '102', bedrooms: 2, rentCents: 180000 };
const U3: Unit = { id: 'u3', number: '201', bedrooms: 2, rentCents: 190000 };

const T1: User = { id: 't1', name: 'Alex Rivera', email: 'tenant1@demo', role: 'tenant' };
const T2: User = { id: 't2', name: 'Bailey Chen', email: 'tenant2@demo', role: 'tenant' };
const T3: User = { id: 't3', name: 'Casey Morgan', email: 'tenant3@demo', role: 'tenant' };

const LEASES: Lease[] = [
  { id: 'l1', unitId: 'u1', unit: U1, tenantId: 't1', tenant: T1, startsOn: '2025-01-01', endsOn: '2026-12-31', rentCents: 120000, dueDay: 1, balanceCents: 120000, status: 'current' },
  { id: 'l2', unitId: 'u2', unit: U2, tenantId: 't2', tenant: T2, startsOn: '2025-03-01', endsOn: '2026-02-28', rentCents: 180000, dueDay: 1, balanceCents: 0, status: 'current' },
  { id: 'l3', unitId: 'u3', unit: U3, tenantId: 't3', tenant: T3, startsOn: '2024-06-01', endsOn: '2026-05-31', rentCents: 190000, dueDay: 1, balanceCents: 240000, status: 'delinquent' },
];

const LEDGERS: Record<string, LedgerEntry[]> = {
  l1: [
    { id: 'l1-e1', leaseId: 'l1', type: 'charge', amountCents: 120000, postedOn: '2026-06-01', period: '2026-06', note: 'Rent — June 2026' },
    { id: 'l1-e2', leaseId: 'l1', type: 'payment', amountCents: 120000, postedOn: '2026-06-03', note: 'Payment received', receiptId: 'r1' },
    { id: 'l1-e3', leaseId: 'l1', type: 'charge', amountCents: 120000, postedOn: '2026-07-01', period: '2026-07', note: 'Rent — July 2026' },
  ],
  l2: [
    { id: 'l2-e1', leaseId: 'l2', type: 'charge', amountCents: 180000, postedOn: '2026-07-01', period: '2026-07', note: 'Rent — July 2026' },
    { id: 'l2-e2', leaseId: 'l2', type: 'payment', amountCents: 180000, postedOn: '2026-07-02', note: 'Payment received', receiptId: 'r2' },
  ],
  l3: [
    { id: 'l3-e1', leaseId: 'l3', type: 'charge', amountCents: 190000, postedOn: '2026-06-01', period: '2026-06', note: 'Rent — June 2026' },
    { id: 'l3-e2', leaseId: 'l3', type: 'lateFee', amountCents: 5000, postedOn: '2026-06-06', note: 'Late fee — June 2026' },
    { id: 'l3-e3', leaseId: 'l3', type: 'charge', amountCents: 190000, postedOn: '2026-07-01', period: '2026-07', note: 'Rent — July 2026' },
    { id: 'l3-e4', leaseId: 'l3', type: 'payment', amountCents: 145000, postedOn: '2026-07-04', note: 'Partial payment', receiptId: 'r3' },
  ],
};

@Component({
  selector: 'app-lease-detail',
  standalone: true,
  imports: [CommonModule, RouterLink, CentsPipe],
  templateUrl: './lease-detail.component.html',
  styleUrl: './lease-detail.component.css',
})
export class LeaseDetailComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal('');

  readonly lease = signal<Lease | null>(null);
  readonly ledger = signal<LedgerEntry[]>([]);

  constructor(private route: ActivatedRoute) {}

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    const found = LEASES.find((l) => l.id === id) ?? null;
    if (!found) {
      this.error.set('Lease not found.');
      return;
    }
    this.lease.set(found);
    this.ledger.set(LEDGERS[found.id] ?? []);
  }

  badgeClass(type: LedgerEntry['type']): string {
    switch (type) {
      case 'payment':
        return 'badge-ok';
      case 'lateFee':
        return 'badge-danger';
      default:
        return 'badge-info';
    }
  }

  typeLabel(type: LedgerEntry['type']): string {
    switch (type) {
      case 'payment':
        return 'Payment';
      case 'lateFee':
        return 'Late fee';
      default:
        return 'Charge';
    }
  }

  statusBadge(status: Lease['status']): string {
    return status === 'delinquent' ? 'badge-danger' : 'badge-ok';
  }

  statusLabel(status: Lease['status']): string {
    return status === 'delinquent' ? 'Delinquent' : 'Current';
  }
}
